prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(CONTAINS(STR(?normId), "4ccc3fd7") OR CONTAINS(STR(?origId), "4ccc3fd7"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(STR(?normId) = "4ccc3fd711004f519782ac92e58f6ddd" || STR(?origId) = "4ccc3fd711004f519782ac92e58f6ddd")
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?flow ?flowId ?source ?target ?targetName ?condition ?conditionExpr ?default WHERE {
  ?flow a bbo:SequenceFlow .
  ?flow bbo:has_sourceRef ?source .
  ?flow bbo:has_targetRef ?target .
  ?source a bboExt:ExclusiveGateway .
  ?target bbo:name "Informieren über Zustimmung" .

  OPTIONAL { ?flow bbo:id ?flowId . }
  OPTIONAL { ?flow bboExt:isImmediate ?condition . }
  OPTIONAL { ?flow bbo:conditionExpression ?conditionExpr . }
  OPTIONAL { ?source bboExt:default ?default . }
}
LIMIT 25
